// --- types.d.ts ---
import { ReactNode } from 'react';

export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string; // 'C' | 'F'
  forecast: ForecastItem[];
}

export interface ForecastDayProps {
  item: ForecastItem;
  unit: string;
}

export interface HookReturn {
  formattedTemp: string;
  conditionIcon: string;
  unit: string;
  forecast: ForecastItem[];
  humidityLabel: string;
  windSpeedLabel: string;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

/**
 * Mapping of weather conditions to their respective icons/emojis.
 */
export const WEATHER_ICONS: Record<string, string> = {
  Sunny: '☀️',
  Cloudy: '☁️',
  Rainy: '🌧️',
  Snowy: '❄️',
  'Partly Cloudy': '⛅',
  Stormy: '⛈️',
  Default: '🌡️',
};

/**
 * Labels for temperature units.
 */
export const UNIT_LABELS: Record<string, string> = {
  C: '°C',
  F: '°F',
};

/**
 * Common labels for weather attributes.
 */
export const WEATHER_LABELS = {
  HUMIDITY: 'Humidity',
  WIND_SPEED: 'Wind Speed',
};


// --- hooks.ts ---
import { WeatherCardProps, HookReturn } from './types';

/**
 * Mapping of weather conditions to icon names from a design system or icon library.
 */
const CONDITION_ICONS: Record<string, string> = {
  sunny: 'Sun',
  clear: 'Sun',
  'partly cloudy': 'CloudSun',
  cloudy: 'Cloud',
  rainy: 'CloudRain',
  showers: 'CloudDrizzle',
  stormy: 'CloudLightning',
  snowy: 'CloudSnow',
  mist: 'CloudFog',
  fog: 'CloudFog',
  windy: 'Wind',
};

/**
 * Custom hook to process weather data for the WeatherCard component.
 * Transforms raw props into formatted strings and UI-ready values.
 */
export function useWeather(props: WeatherCardProps): HookReturn {
  const {
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  // Format temperature with rounding and unit suffix (e.g., "22°C")
  const formattedTemp = `${Math.round(temperature)}°${unit}`;

  // Map the condition string to a specific icon name
  const conditionLower = (condition || '').toLowerCase();
  const conditionIcon = CONDITION_ICONS[conditionLower] || 'Cloud';

  // Format humidity as a percentage string
  const humidityLabel = `${humidity}%`;

  // Format wind speed with appropriate units based on temperature unit
  // Defaulting to km/h for Metric (C) and mph for Imperial (F)
  const windSpeedLabel = `${windSpeed} ${unit === 'F' ? 'mph' : 'km/h'}`;

  return {
    formattedTemp,
    conditionIcon,
    unit,
    forecast,
    humidityLabel,
    windSpeedLabel,
  };
}


// --- ForecastDay.tsx ---
import React from 'react';
import { Stack, Text, Box } from '@ggui-ai/design/primitives';
import type { ForecastDayProps } from './types';

/**
 * ForecastDay renders a single day's weather summary in a vertical stack.
 * Displays the day name, weather icon/emoji, and high/low temperature ranges.
 */
export function ForecastDay({ item, unit }: ForecastDayProps) {
  return (
    <Box padding={8}>
      <Stack direction="vertical" align="center" gap={8}>
        {/* Day Name */}
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {item.day}
        </Text>

        {/* Weather Icon/Emoji */}
        <Text size="3xl" aria-hidden="true">
          {item.icon}
        </Text>

        {/* Temperature Range */}
        <Stack direction="vertical" align="center" gap={2}>
          {/* Warm color for high temperature */}
          <Text weight="bold" color="var(--ggui-color-error-600, #dc2626)">
            {item.high}°{unit}
          </Text>
          {/* Cool color for low temperature */}
          <Text variant="caption" weight="medium" color="var(--ggui-color-primary-600, #0284c7)">
            {item.low}°{unit}
          </Text>
        </Stack>
      </Stack>
    </Box>
  );
}


// --- ui.tsx ---
import React from 'react';
import type { WeatherCardProps, HookReturn } from './types';
import { ForecastDay } from './ForecastDay';
import {
  Card,
  Stack,
  Heading,
  Text,
  Icon,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';

export function ComponentUI(props: WeatherCardProps & HookReturn) {
  const {
    city,
    condition,
    formattedTemp,
    conditionIcon,
    unit,
    forecast,
    humidityLabel,
    windSpeedLabel,
  } = props;

  return (
    <Card padding={24} shadow="md" radius="xl" border>
      <Stack gap={24}>
        {/* Header Section: City, Temperature and Condition */}
        <Stack align="center" gap={8}>
          <Heading level={2} align="center">
            {city}
          </Heading>
          <Heading
            level={1}
            align="center"
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {formattedTemp}
          </Heading>
          <Stack direction="horizontal" align="center" gap={8}>
            <Icon
              name={conditionIcon}
              size={24}
              color="var(--ggui-color-neutral-500, #6b7280)"
            />
            <Text variant="bodyLarge" weight="medium">
              {condition}
            </Text>
          </Stack>
        </Stack>

        <Divider margin={0} />

        {/* Detailed Stats Section */}
        <Stack direction="horizontal" justify="around" gap={16}>
          <Stack gap={4} align="center">
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text variant="label" weight="semibold">
              {humidityLabel}
            </Text>
          </Stack>
          <Divider orientation="vertical" margin={0} />
          <Stack gap={4} align="center">
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
            <Text variant="label" weight="semibold">
              {windSpeedLabel}
            </Text>
          </Stack>
        </Stack>

        <Divider margin={0} />

        {/* Forecast Section */}
        <Box>
          <Stack gap={16}>
            <Text
              variant="overline"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              5-Day Forecast
            </Text>
            <Stack
              direction="horizontal"
              justify="between"
              gap={12}
              wrap
              align="start"
            >
              {forecast.map((item, index) => (
                <ForecastDay
                  key={`${item.day}-${index}`}
                  item={item}
                  unit={unit}
                />
              ))}
            </Stack>
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
